package consistent

import "testing"

func TestTotalLoadTracksWithinBoundAssignments(t *testing.T) {
	h := NewBoundedLoadHash(3, 100.0)
	members := []string{"node-a"}
	h.Add(members[0])

	for i, key := range []string{"alpha", "bravo", "charlie", "delta", "echo"} {
		if got := h.Get(key); got == "" {
			t.Fatalf("Get(%q) returned empty node", key)
		}
		assertTotalLoadEqualsNodeLoads(t, h, members, i+1)
	}
}

func TestTotalLoadTracksMixedAssignmentReleaseAndRemoval(t *testing.T) {
	h := NewBoundedLoadHash(5, 100.0)
	members := []string{"node-a", "node-b", "node-c"}
	for _, member := range members {
		h.Add(member)
	}

	assignments := make([]string, 0, 6)
	for _, key := range []string{"alpha", "bravo", "charlie", "delta", "echo", "foxtrot"} {
		assignments = append(assignments, h.Get(key))
	}
	assertTotalLoadEqualsNodeLoads(t, h, members, len(assignments))

	h.Release(assignments[1])
	assertTotalLoadEqualsNodeLoads(t, h, members, len(assignments)-1)

	h.Release(assignments[4])
	assertTotalLoadEqualsNodeLoads(t, h, members, len(assignments)-2)

	removed := assignments[0]
	h.Remove(removed)
	remainingMembers := filterMember(members, removed)
	assertTotalLoadEqualsNodeLoads(t, h, remainingMembers, sumLoads(h, remainingMembers))
}

func TestTotalLoadTracksWithinBoundAndOverBoundBoundary(t *testing.T) {
	h := NewBoundedLoadHash(1, 1.0)
	members := []string{"node-a", "node-b"}
	for _, member := range members {
		h.Add(member)
	}

	for i, key := range []string{"alpha", "bravo", "charlie"} {
		if got := h.Get(key); got == "" {
			t.Fatalf("Get(%q) returned empty node", key)
		}
		assertTotalLoadEqualsNodeLoads(t, h, members, i+1)
	}
}

func assertTotalLoadEqualsNodeLoads(t *testing.T, h *BoundedLoadHash, members []string, want int) {
	t.Helper()

	sum := sumLoads(h, members)
	if sum != want {
		t.Fatalf("sum of node loads = %d, want %d", sum, want)
	}
	if got := h.TotalLoad(); got != sum {
		t.Fatalf("TotalLoad() = %d, want sum of node loads %d", got, sum)
	}
}

func sumLoads(h *BoundedLoadHash, members []string) int {
	sum := 0
	for _, member := range members {
		sum += h.Load(member)
	}
	return sum
}

func filterMember(members []string, removed string) []string {
	filtered := make([]string, 0, len(members))
	for _, member := range members {
		if member != removed {
			filtered = append(filtered, member)
		}
	}
	return filtered
}

