func (h *BoundedLoadHash) Size() int { h.mu.RLock(); defer h.mu.RUnlock(); return h.memberCount }

func (h *BoundedLoadHash) maxLoadPerNode() int {
	if h.memberCount == 0 {
		return 1
	}
	avg := float64(h.totalLoad+1) / float64(h.memberCount)
	if avg < 1 {
		avg = 1
	}
	return int(avg * h.loadFactor)
}

